import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"圆明园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/index.md","filePath":"landmarks/yuanmingyuan/index.md","lastUpdated":1784720050000}'),r={name:"landmarks/yuanmingyuan/index.md"};function d(s,t,i,o,g,h){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="圆明园" tabindex="-1">圆明园 <a class="header-anchor" href="#圆明园" aria-label="Permalink to &quot;圆明园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1747001539757-285c9443a55b?w=1200&amp;q=80" alt="圆明园遗址"></p><blockquote><p>&quot;有一天，两个强盗闯进了圆明园，一个强盗洗劫，另一个强盗放火……在历史面前，这两个强盗一个叫法兰西，一个叫英吉利。&quot; —— 维克多·雨果《就英法联军远征中国给巴特勒上尉的信》（1861年）</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>圆明园位于北京西北郊，与<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园</a>毗邻，由<strong>圆明园、长春园、绮春园</strong>三园组成，统称&quot;圆明三园&quot;，占地350多公顷，其中水面面积约140公顷，建筑面积达20万平方米。自康熙四十八年（1709年）始建，历经雍正、乾隆、嘉庆、道光、咸丰五朝150余年营建，园中有景观150余处，曾被誉为&quot;万园之园&quot;和&quot;一切造园艺术的典范&quot;。</p><p>1860年10月，英法联军攻入北京，对圆明园大肆劫掠后纵火焚毁，大火三日三夜不熄。1900年八国联军侵华期间，园内残存建筑再遭洗劫。曾经的琼楼玉宇，如今只剩断壁残垣静立于荒草之间。</p><p>今天的圆明园是<strong>全国重点文物保护单位</strong>和<strong>爱国主义教育基地</strong>。那些矗立在夕阳下的大理石残柱，无声地诉说着那段屈辱的历史，提醒后人：勿忘国耻，吾辈自强。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">旺季（4月-10月）7:00-19:00；淡季（11月-3月）7:00-17:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">大门门票10元；西洋楼遗址15元；全景模型展10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">精华游3小时，深度游5-6小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">夏赏荷、秋观银杏、春踏青</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线圆明园站B口出，步行约5分钟至南门</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">可通过官方公众号或现场购票</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">详情</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大水法</strong></td><td style="text-align:left;">西洋楼主景，欧式喷泉遗址，圆明园的标志</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">查看详情</a></td></tr><tr><td style="text-align:left;"><strong>海晏堂与十二生肖兽首</strong></td><td style="text-align:left;">西洋楼最大建筑，兽首喷泉与流失海外的国宝</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">查看详情</a></td></tr><tr><td style="text-align:left;"><strong>西洋楼建筑群</strong></td><td style="text-align:left;">圆明园唯一西式景区，巴洛克风格园林</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">查看详情</a></td></tr><tr><td style="text-align:left;"><strong>福海景区</strong></td><td style="text-align:left;">园内最大湖面，蓬岛瑶台，端午龙舟竞渡之地</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/fuhai.html">查看详情</a></td></tr><tr><td style="text-align:left;"><strong>绮春园</strong></td><td style="text-align:left;">正觉寺（唯一幸存古建筑群），赏荷佳处</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/qichun-yuan.html">查看详情</a></td></tr><tr><td style="text-align:left;"><strong>文源阁</strong></td><td style="text-align:left;">曾藏《四库全书》，&quot;南北七阁&quot;之一</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/wenyuan-ge.html">查看详情</a></td></tr></tbody></table><h2 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h2><h3 id="精华游-约3小时" tabindex="-1">精华游（约3小时） <a class="header-anchor" href="#精华游-约3小时" aria-label="Permalink to &quot;精华游（约3小时）&quot;">​</a></h3><p>地铁4号线圆明园站 → 南门入园 → <strong>绮春园</strong>（正觉寺）→ 三园交界 → 福海西岸漫步 → <strong>西洋楼遗址区</strong>（谐奇趣 → 万花阵 → 海晏堂 → <strong>大水法</strong> → 远瀛观）→ 东门出</p><blockquote><p>💡 此路线以西洋楼遗址为核心，是绝大多数游客的选择。遗址区需另购15元门票。</p></blockquote><h3 id="深度游-约5-6小时" tabindex="-1">深度游（约5-6小时） <a class="header-anchor" href="#深度游-约5-6小时" aria-label="Permalink to &quot;深度游（约5-6小时）&quot;">​</a></h3><p>南门 → <strong>绮春园</strong>（正觉寺、鉴碧亭）→ <strong>福海景区</strong>（蓬岛瑶台环湖）→ 方外观 → 养雀笼 → <strong>西洋楼全景区</strong>（谐奇趣、蓄水楼、万花阵、海晏堂、大水法、观水法、线法山）→ <strong>文源阁</strong>遗址 → 圆明园博物馆（全景模型展）→ 南门出</p><blockquote><p>💡 园区面积广阔，深度游建议乘坐园内观光电瓶车（10-15元/站）节省体力。</p></blockquote><h2 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h2><p>圆明园不仅是一座园林，更是一段民族记忆的载体：</p><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1709年</td><td style="text-align:left;">康熙帝赐园予皇四子胤禛（后来的雍正帝），&quot;圆明&quot;二字为康熙御笔</td></tr><tr><td style="text-align:left;">1709-1860年</td><td style="text-align:left;">历经五朝150余年营建，成为&quot;万园之园&quot;，清代政治中心之一</td></tr><tr><td style="text-align:left;">1860年10月</td><td style="text-align:left;">英法联军劫掠焚毁，大火三日不熄</td></tr><tr><td style="text-align:left;">1900年</td><td style="text-align:left;">八国联军侵华，残存建筑再遭劫掠</td></tr><tr><td style="text-align:left;">1976年</td><td style="text-align:left;">成立圆明园管理处，开始系统保护</td></tr><tr><td style="text-align:left;">1988年</td><td style="text-align:left;">被国务院列为全国重点文物保护单位</td></tr></tbody></table><p>圆明园的毁灭是中华民族的奇耻大辱，也是人类文明史上的一场浩劫。今天的遗址公园选择&quot;保留残迹、不事重建&quot;，让每一块残石都成为历史的见证。正如雨果所言，这是&quot;世界文明史上的惨痛损失&quot;。</p><p>更多圆明园的历史，可参阅<a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>。</p><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">保存最完整的皇家园林</td></tr><tr><td style="text-align:left;">清华大学</td><td style="text-align:center;">约1公里</td><td style="text-align:left;">百年学府，荷塘月色</td></tr><tr><td style="text-align:left;">北京大学</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">未名湖、博雅塔</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区清华西路28号 <strong>📞 电话</strong>：010-62543673 <strong>🌐 官网</strong>：<a href="http://www.yuanmingyuanpark.com" target="_blank" rel="noreferrer">www.yuanmingyuanpark.com</a></p><p><strong>💡 提示</strong>：圆明园是遗址公园，请以庄重之心游览。西洋楼遗址区的大理石残构件极其珍贵，请勿攀爬触摸。</p>',28)])])}const f=e(r,[["render",d]]);export{u as __pageData,f as default};
